import React, { useEffect, useState } from 'react';
import '../styles/components/Hero.css';

const Hero = () => {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  useEffect(() => {
    // #region agent log
    const heroEl = document.querySelector('.hero'); const heroContent = document.querySelector('.hero-content'); const heroTitle = document.querySelector('.hero-title'); fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'Hero.jsx:useEffect',message:'Hero mounted - checking DOM',data:{heroExists:!!heroEl,heroContentExists:!!heroContent,heroTitleExists:!!heroTitle,heroZIndex:heroEl?getComputedStyle(heroEl).zIndex:'N/A',contentZIndex:heroContent?getComputedStyle(heroContent).zIndex:'N/A'},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'C'})}).catch(()=>{});
    // #endregion

    // #region agent log
    const bodyBg = getComputedStyle(document.body).backgroundColor; const heroBg = heroEl?getComputedStyle(heroEl).backgroundColor:'N/A'; const titleColor = heroTitle?getComputedStyle(heroTitle).color:'N/A'; const orbEl = document.querySelector('.gradient-orb'); const orbBg = orbEl?getComputedStyle(orbEl).backgroundColor:'N/A'; const orbZIndex = orbEl?getComputedStyle(orbEl).zIndex:'N/A'; fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'Hero.jsx:useEffect',message:'Checking colors and gradient orb',data:{bodyBg,heroBg,titleColor,orbExists:!!orbEl,orbBg,orbZIndex,contentZIndex:heroContent?getComputedStyle(heroContent).zIndex:'N/A'},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'E'})}).catch(()=>{});
    // #endregion

    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth) * 100,
        y: (e.clientY / window.innerHeight) * 100,
      });
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  const scrollToSection = (sectionId) => {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  };

  return (
    <section id="home" className="hero">
      <div className="hero-background">
        <div className="particles">
          {[...Array(50)].map((_, i) => (
            <div key={i} className="particle" style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              animationDelay: `${Math.random() * 3}s`,
              animationDuration: `${3 + Math.random() * 4}s`
            }}></div>
          ))}
        </div>
        <div 
          className="gradient-orb"
          style={{
            left: `${mousePosition.x}%`,
            top: `${mousePosition.y}%`,
          }}
        ></div>
      </div>

      <div className="hero-content">
        <div className="hero-text">
          <h1 className="hero-title">
            <span className="title-line">Aarav Sahni</span>
          </h1>
          <p className="hero-subtitle">
            Your local tech and aviation enthusiast
          </p>
          <div className="hero-buttons">
            <button 
              className="btn btn-secondary"
              onClick={() => scrollToSection('about')}
            >
              <span className="btn-primary-text">ABOUT</span>
              <span className="btn-primary-text">ME</span>
              <span className="btn-secondary-text">BELL CUTOUT</span>
            </button>
            <button 
              className="btn btn-primary"
              onClick={() => scrollToSection('skills')}
            >
              <span className="btn-primary-text">LANGUAGES/</span>
              <span className="btn-primary-text">SKILLS</span>
              <span className="btn-secondary-text">PUSH TO RESET</span>
            </button>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
